    public static class TimestampValidator {

        // Maximum allowed clock skew between client and server
        private static final Duration MAX_CLOCK_SKEW = Duration.ofSeconds(60);

        // Maximum allowed message age
        private static final Duration MAX_MESSAGE_AGE = Duration.ofMinutes(5);

        // Minimum required timestamp validity window
        private static final Duration MIN_VALIDITY_WINDOW = Duration.ofSeconds(1);

        // Maximum allowed expiry window to prevent far-future timestamps
        private static final Duration MAX_EXPIRY_WINDOW = Duration.ofMinutes(10);

        // Cache of recently seen message IDs for replay detection
        // In production, use a distributed cache (e.g., Redis) with TTL
        private final ConcurrentHashMap<String, Instant> replayCache = new ConcurrentHashMap<>();

        // Maximum replay cache size to prevent memory exhaustion
        private static final int MAX_CACHE_SIZE = 100_000;

        /**
         * Validates the timestamp info against security constraints.
         * Returns null if valid, or an error message if invalid.
         */
        public String validate(TimestampInfo timestampInfo) {
            if (timestampInfo == null) {
                return "Missing WS-Security timestamp";
            }

            Instant created = timestampInfo.getCreated();
            Instant expires = timestampInfo.getExpires();
            String messageId = timestampInfo.getMessageId();

            if (created == null) {
                return "Missing Created timestamp";
            }

            if (expires == null) {
                return "Missing Expires timestamp";
            }

            if (messageId == null || messageId.trim().isEmpty()) {
                return "Missing message identifier";
            }

            Instant now = Instant.now();

            // 1. Validate Created is not in the future (with clock skew allowance)
            if (created.isAfter(now.plus(MAX_CLOCK_SKEW))) {
                return "Created timestamp is in the future";
            }

            // 2. Validate message is not too old
            if (created.isBefore(now.minus(MAX_MESSAGE_AGE))) {
                return "Message timestamp is too old";
            }

            // 3. Validate Expires is after Created
            if (!expires.isAfter(created)) {
                return "Expires must be after Created";
            }

            // 4. Validate the validity window is reasonable (not too short)
            Duration validityWindow = Duration.between(created, expires);
            if (validityWindow.compareTo(MIN_VALIDITY_WINDOW) < 0) {
                return "Timestamp validity window is too short";
            }

            // 5. Validate the expiry is not too far in the future (prevents manipulation)
            if (expires.isAfter(now.plus(MAX_EXPIRY_WINDOW))) {
                return "Expires timestamp is too far in the future";
            }

            // 6. Validate the message has not expired (with clock skew allowance)
            if (expires.isBefore(now.minus(MAX_CLOCK_SKEW))) {
                return "Message has expired";
            }

            // 7. Replay detection: check if this message ID was already processed
            if (isReplay(messageId, expires)) {
                return "Replay attack detected: duplicate message identifier";
            }

            return null; // Valid
        }

        /**
         * Checks for replay attacks using message ID tracking.
         * Returns true if this is a replayed message.
         */
        private boolean isReplay(String messageId, Instant expires) {
            // Sanitize message ID - only allow alphanumeric, hyphens, underscores
            if (!messageId.matches("^[a-zA-Z0-9\\-_]{1,256}$")) {
                // Treat invalid message IDs as potential attacks
                return true;
            }

            // Evict expired entries periodically
            evictExpiredEntries();

            // Check cache size to prevent memory exhaustion
            if (replayCache.size() >= MAX_CACHE_SIZE) {
                LOGGER.warning("Replay cache is at capacity. Forcing eviction.");
                evictExpiredEntries();
                if (replayCache.size() >= MAX_CACHE_SIZE) {
                    // Still full after eviction - reject to be safe
                    LOGGER.severe("Replay cache overflow. Rejecting message for safety.");
                    return true;
                }
            }

            // Attempt to insert; if already present, it's a replay
            Instant previous = replayCache.putIfAbsent(messageId, expires);
            return previous != null;
        }

        /**
         * Removes expired entries from the replay cache.
         */
        private void evictExpiredEntries() {
            Instant now = Instant.now();
            replayCache.entrySet().removeIf(entry ->
                entry.getValue().isBefore(now.minus(MAX_MESSAGE_AGE))
            );
        }
    }

