    // --- Input Validator ---

    public static class PaymentInputValidator {

        // Allowlist of supported currencies (ISO 4217)
        private static final Set<String> ALLOWED_CURRENCIES = Set.of(
            "USD", "EUR", "GBP", "CAD", "AUD", "JPY", "CHF"
        );

        // Maximum transaction amount
        private static final BigDecimal MAX_AMOUNT = new BigDecimal("999999.99");

        // Minimum transaction amount
        private static final BigDecimal MIN_AMOUNT = new BigDecimal("0.01");

        // Allowed characters for string fields
        private static final String ALPHANUMERIC_PATTERN = "^[a-zA-Z0-9\\-_]{1,64}$";
        private static final String DESCRIPTION_PATTERN = "^[a-zA-Z0-9\\s\\-_.,]{0,256}$";
        private static final String TOKEN_PATTERN = "^tok_[a-zA-Z0-9]{16,64}$";

        public static String validatePaymentRequest(PaymentRequest request) {
            if (request == null) {
                return "Payment request is required";
            }

            // Validate merchant ID
            if (request.getMerchantId() == null || !request.getMerchantId().matches(ALPHANUMERIC_PATTERN)) {
                return "Invalid merchant ID format";
            }

            // Validate transaction ID
            if (request.getTransactionId() == null || !request.getTransactionId().matches(ALPHANUMERIC_PATTERN)) {
                return "Invalid transaction ID format";
            }

            // Validate amount
            if (request.getAmount() == null) {
                return "Amount is required";
            }
            if (request.getAmount().compareTo(MIN_AMOUNT) < 0) {
                return "Amount must be at least " + MIN_AMOUNT;
            }
            if (request.getAmount().compareTo(MAX_AMOUNT) > 0) {
                return "Amount exceeds maximum allowed";
            }
            if (request.getAmount().scale() > 2) {
                return "Amount must have at most 2 decimal places";
            }

            // Validate currency against allowlist
            if (request.getCurrency() == null || !ALLOWED_CURRENCIES.contains(request.getCurrency())) {
                return "Unsupported currency. Allowed: " + ALLOWED_CURRENCIES;
            }

            // Validate card token reference format
            if (request.getCardTokenReference() == null || !request.getCardTokenReference().matches(TOKEN_PATTERN)) {
                return "Invalid card token reference format";
            }

            // Validate description (optional but must be safe if present)
            if (request.getDescription() != null && !request.getDescription().matches(DESCRIPTION_PATTERN)) {
                return "Invalid characters in description";
            }

            return null; // Valid
        }

        public static String validateTransactionId(String transactionId) {
            if (transactionId == null || !transactionId.matches(ALPHANUMERIC_PATTERN)) {
                return "Invalid transaction ID format";
            }
            return null;
        }

        public static String validateRefundAmount(BigDecimal amount) {
            if (amount == null) {
                return "Refund amount is required";
            }
            if (amount.compareTo(MIN_AMOUNT) < 0) {
                return "Refund amount must be at least " + MIN_AMOUNT;
            }
            if (amount.compareTo(MAX_AMOUNT) > 0) {
                return "Refund amount exceeds maximum allowed";
            }
            if (amount.scale() > 2) {
                return "Amount must have at most 2 decimal places";
            }
            return null;
        }
    }

    // --- Payment Service Implementation ---

    @WebService(
        endpointInterface = "PaymentProcessingService$PaymentServiceInterface",
        serviceName = "PaymentService",
        portName = "PaymentServicePort",
        targetNamespace = "urn:payment:service"
    )
    public static class PaymentServiceImpl implements PaymentServiceInterface {

        private static final SecureRandom secureRandom = new SecureRandom();

        // In production, this would be backed by a database
        private final ConcurrentHashMap<String, PaymentResponse> transactionStore = new ConcurrentHashMap<>();

        @Override
        public PaymentResponse processPayment(PaymentRequest request) throws PaymentFault {
            // Validate all input
            String validationError = PaymentInputValidator.validatePaymentRequest(request);
            if (validationError != null) {
                LOGGER.warning("Payment validation failed: " + validationError);
                throw new PaymentFault(validationError, "VALIDATION_ERROR");
            }

            // Check for duplicate transaction ID (idempotency)
            if (transactionStore.containsKey(request.getTransactionId())) {
                PaymentResponse existing = transactionStore.get(request.getTransactionId());
                LOGGER.info("Returning existing response for duplicate transaction: " + request.getTransactionId());
                return existing;
            }

            // Process payment (in production, this would call the payment processor)
            PaymentResponse response = new PaymentResponse();
            response.setTransactionId(request.getTransactionId());
            response.setProcessedAt(Instant.now());

            try {
                // Simulate payment processing
                String authCode = generateAuthorizationCode();
                response.setStatus("APPROVED");
                response.setAuthorizationCode(authCode);
                response.setMessage("Payment processed successfully");

                // Log without sensitive data
                LOGGER.info("Payment processed: txn=" + request.getTransactionId()
                    + " merchant=" + request.getMerchantId()
                    + " amount=" + request.getAmount()
                    + " currency=" + request.getCurrency()
                    + " status=APPROVED");

            } catch (Exception e) {
                response.setStatus("DECLINED");
                response.setMessage("Payment processing failed");
                LOGGER.log(Level.WARNING, "Payment processing error for txn=" + request.getTransactionId(), e);
            }

            // Store for idempotency and status queries
            transactionStore.put(request.getTransactionId(), response);

            return response;
        }

        @Override
        public PaymentResponse refundPayment(String transactionId, BigDecimal amount) throws PaymentFault {
            // Validate inputs
            String txnError = PaymentInputValidator.validateTransactionId(transactionId);
            if (txnError != null) {
                throw new PaymentFault(txnError, "VALIDATION_ERROR");
            }

            String amountError = PaymentInputValidator.validateRefundAmount(amount);
            if (amountError != null) {
                throw new PaymentFault(amountError, "VALIDATION_ERROR");
            }

            // Check original transaction exists
            PaymentResponse originalTxn = transactionStore.get(transactionId);
            if (originalTxn == null) {
                throw new PaymentFault("Original transaction not found", "NOT_FOUND");
            }

            if (!"APPROVED".equals(originalTxn.getStatus())) {
                throw new PaymentFault("Cannot refund a transaction that was not approved", "INVALID_STATE");
            }

            PaymentResponse response = new PaymentResponse();
            response.setTransactionId("REF-" + transactionId);
            response.setStatus("REFUNDED");
            response.setAuthorizationCode(generateAuthorizationCode());
            response.setMessage("Refund processed successfully");
            response.setProcessedAt(Instant.now());

            LOGGER.info("Refund processed: original_txn=" + transactionId + " amount=" + amount);

            return response;
        }

        @Override
        public PaymentResponse getTransactionStatus(String transactionId) throws PaymentFault {
            String txnError = PaymentInputValidator.validateTransactionId(transactionId);
            if (txnError != null) {
                throw new PaymentFault(txnError, "VALIDATION_ERROR");
            }

            PaymentResponse response = transactionStore.get(transactionId);
            if (response == null) {
                throw new PaymentFault("Transaction not found", "NOT_FOUND");
            }

            return response;
        }

        private String generateAuthorizationCode() {
            byte[] bytes = new byte[8];
            secureRandom.nextBytes(bytes);
            StringBuilder sb = new StringBuilder();
            for (byte b : bytes) {
                sb.append(String.format("%02X", b));
            }
            return sb.toString();
        }
    }

    // --- SOAP Message Builder (for testing/client use) ---

    public static class SecureSoapMessageBuilder {

        private static final String WSU_NAMESPACE = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
        private static final String WSSE_NAMESPACE = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";

        /**
         * Adds a WS-Security timestamp header to a SOAP message.
         */
        public static void addSecurityTimestamp(SOAPMessage message, Duration validityDuration) throws SOAPException {
            if (validityDuration == null || validityDuration.isNegative() || validityDuration.isZero()) {
                throw new IllegalArgumentException("Validity duration must be positive");
            }

            SOAPHeader header = message.getSOAPHeader();
            if (header == null) {
                header = message.getSOAPPart().getEnvelope().addHeader();
            }

            // Create wsse:Security header
            SOAPHeaderElement securityHeader = header.addHeaderElement(
                new QName(WSSE_NAMESPACE, "Security", "wsse")
            );
            securityHeader.setMustUnderstand(true);

            // Create wsu:Timestamp
            SOAPElement timestamp = securityHeader.addChildElement("Timestamp", "wsu", WSU_NAMESPACE);

            // Generate a unique message ID
            String messageId = "TS-" + UUID.randomUUID().toString();
            timestamp.addAttribute(new QName(WSU_NAMESPACE, "Id", "wsu"), messageId);

            Instant now = Instant.now();
            Instant expires = now.plus(validityDuration);

            // Add Created
            SOAPElement created = timestamp.addChildElement("Created", "wsu", WSU_NAMESPACE);
            created.setTextContent(now.toString());

            // Add Expires
            SOAPElement expiresElement = timestamp.addChildElement("Expires", "wsu", WSU_NAMESPACE);
            expiresElement.setTextContent(expires.toString());

            message.saveChanges();
        }
    }

